create table dirkspzm32.fls_element_cfg (
    sid                           varchar2(2 char) not null enable,
    firma_nr                      number not null enable,
    instance_id                   number(*, 0) not null enable,
    reset_gruppen_id              number(*, 0) default 1 not null enable,
    element_id                    number(*, 0) not null enable,
    res_id                        number(*, 0),
    enabled                       varchar2(1 char) default 'T' not null enable,
    editor_sperre                 varchar2(1 char) default 'F' not null enable,
    element_typ                   varchar2(5 char) not null enable,
    element_ix                    number(*, 5) not null enable,
    element_name                  varchar2(40 char) not null enable,
    kurzname                      varchar2(8 char),
    gewerke_nr                    number(*, 5) not null enable,
    pos_nr                        number(*, 0) default 0 not null enable,
    max_fe                        number(*, 5) default 1 not null enable,
    auftr_art                     number(*, 5) default 0 not null enable,
    grob_fein                     number(*, 5) default 0 not null enable,
    geschwindigkeit_cm_pro_min    number(*, 12) default 0 not null enable,
    progr_nr                      number(*, 5) default 0 not null enable,
    telegr_mt_belegt              number(*, 5) default 0 not null enable,
    telegr_mt_freiplatz           number(*, 5) default 0 not null enable,
    telegr_mt_abmeldung           number(*, 5) default 0 not null enable,
    telegr_fc                     number(*, 5) default 0 not null enable,
    telegr_fe_id_anfang           number(*, 0) default 0 not null enable,
    telegr_fe_id_ende             number(*, 0) default 0 not null enable,
    telegr_sps_bereich_nr         number(*, 5) default 0 not null enable,
    telegr_meld_nr                number(*, 5) default 1 not null enable,
    telegr_koppl_nr               number(*, 5) default 0 not null enable,
    telegr_konturen_kontrolle     number(*, 5) default 0 not null enable,
    telegr_paletten_typ           number(*, 5) default 0 not null enable,
    telegr_paletten_hoehe         number(*, 5) default 0 not null enable,
    strategie_tourreihenfolge     number(*, 5) default 0 not null enable,
    strategie_einl_ausl_verh      number(*, 5) default 0 not null enable,
    strategie_pkt_belegung        number(*, 5) default 0 not null enable,
    strategie_pkt_warten          number(*, 5) default 0 not null enable,
    strategie_prio_xproz_bef      number(*, 5) default 0 not null enable,
    strategie_pkt_max_proz        number(*, 5) default 1 not null enable,
    strategie_pkt_prio            number(*, 5) default 0 not null enable,
    strategie_pkt_wegopti         number(*, 5) default 0 not null enable,
    simulat_sps_pq_zentel_sek     number(*, 12) default 0 not null enable,
    simulat_sps_mt_zentel_sek     number(*, 12) default 0 not null enable,
    koordinat_pos_x_anfang_cm     number(*, 3) default 0 not null enable,
    koordinat_pos_y_anfang_cm     number(*, 3) default 0 not null enable,
    koordinat_pos_z_anfang_cm     number(*, 3) default 0 not null enable,
    koordinat_pos_x_ende_cm       number(*, 3) default 0 not null enable,
    koordinat_pos_y_ende_cm       number(*, 3) default 0 not null enable,
    koordinat_pos_z_ende_cm       number(*, 3) default 0 not null enable,
    koordinat_bewegung            number(*, 5) default 0 not null enable,
    koordinat_gesamtlaenge_cm     number(*, 3) default 0,
    strategie_punktevergabe       number(*, 0) default 1,
    strategie_fls_meld_extern     number(*, 5) default 0 not null enable,
    strategie_defekt_moegl        number(*, 5) default 0 not null enable,
    strategie_pkt_anz_quell_pruef number(*, 5) default 0 not null enable,
    strategie_auftr_timeout_zs    number(*, 12) default 100 not null enable,
    telegr_grundst_moegl          varchar2(1 char) default 'F' not null enable,
    default_ziel_id               number(*, 0),
    is_defekt                     varchar2(1 char) default 'F' not null enable,
    is_holen_gesperrt             varchar2(1 char) default 'F' not null enable,
    is_bringen_gesperrt           varchar2(1 char) default 'F' not null enable,
    is_ipunkt                     number(*, 5) default 0 not null enable,
    is_ziel                       number(*, 0) default 0 not null enable,
    is_aufsetz_punkt              varchar2(1 char) default 'F' not null enable,
    is_entscheid_punkt            number(*, 0) default 0 not null enable,
    aktions_logik                 varchar2(100 char),
    zusatz_logik_namen            varchar2(300 char),
    konfig_params                 varchar2(1024 char),
    telegr_mt_we                  number(*, 5) default 0 not null enable,
    strategie_verl_st_vorg        varchar2(1 char) default 'P' not null enable,
    strategie_lagerplatz          varchar2(100 char),
    default_quell_id              number(*, 0),
    strategie_reihenfolge_von     number(*, 5) default 0 not null enable,
    strategie_reihenfolge_bis     number(*, 5) default 0 not null enable,
    strategie_ausschleus_moegl    number(*, 5) default 0 not null enable,
    is_auto_warenauszeichn        number(*, 5) default 0 not null enable,
    strategie_ausschleus_ziel_id  number(*, 0),
    strategie_ersatz_ziel_id      number(*, 0),
    strategie_auto_transp_ziel_id number(*, 0),
    strategie_scann_betr_waehlen  number(*, 5) default 0 not null enable,
    strategie_durchschl_moeglich  number(*, 0) default 0,
    strategie_defekt_def_ziel_id  number(*, 0),
    visu_logik                    varchar2(100 char)
);

alter table dirkspzm32.fls_element_cfg
    add constraint pk_fls_element_cfg primary key ( element_id )
        using index enable;

alter table dirkspzm32.fls_element_cfg add constraint ux_fls_element_cfg_fahrz unique ( element_name )
    using index enable;

alter table dirkspzm32.fls_element_cfg add constraint ux_fls_element_cfg_res_id unique ( res_id )
    using index enable;


